#!/usr/bin/env node
const expected = Number(argValue('--expected'));
if (expected !== 1) {
  console.error(`[codestral-openai-qspec] reject expected=${expected}; only expected=1 admits`);
  process.exit(2);
}

const baseUrl = stripTrailingSlash(
  process.env.CODESTRAL_OPENAI_BASE_URL ||
    'https://gnosis-openai-mesh-6ptd7xm6fq-uc.a.run.app/v1',
);
const model = process.env.CODESTRAL_QSPEC_MODEL || 'codestral-22b';
const prompt =
  process.env.CODESTRAL_QSPEC_PROMPT ||
  [
    'Return only TypeScript code.',
    'Write a function named clamp that takes value, min, and max numbers and returns value constrained to the inclusive range.',
    'Include explicit number parameter and return types.',
  ].join(' ');
const maxLatencyMs = readPositiveInt('CODESTRAL_QSPEC_MAX_LATENCY_MS', 120_000);
const requestTimeoutMs = readPositiveInt('CODESTRAL_QSPEC_REQUEST_TIMEOUT_MS', maxLatencyMs + 30_000);
const minChars = readPositiveInt('CODESTRAL_QSPEC_MIN_CHARS', 80);
const required = (process.env.CODESTRAL_QSPEC_REQUIRED || 'function,clamp,return,number')
  .split(',')
  .map((part) => part.trim().toLowerCase())
  .filter(Boolean);
const requireClampImpl = process.env.CODESTRAL_QSPEC_REQUIRE_CLAMP_IMPL !== '0';

const started = Date.now();

try {
  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      ...(process.env.CODESTRAL_OPENAI_API_KEY
        ? { authorization: `Bearer ${process.env.CODESTRAL_OPENAI_API_KEY}` }
        : {}),
    },
    body: JSON.stringify({
      model,
      temperature: 0,
      max_tokens: 160,
      messages: [
        {
          role: 'user',
          content: prompt,
        },
      ],
    }),
    signal: AbortSignal.timeout(requestTimeoutMs),
  });

  const elapsedMs = Date.now() - started;
  const text = await response.text();
  if (!response.ok) {
    fail(`HTTP ${response.status} after ${elapsedMs}ms: ${text.slice(0, 600)}`);
  }

  const json = parseJson(text);
  const content = String(json?.choices?.[0]?.message?.content || '').trim();
  const finishReason = json?.choices?.[0]?.finish_reason;

  if (elapsedMs > maxLatencyMs) {
    fail(`latency ${elapsedMs}ms exceeded qspec limit ${maxLatencyMs}ms`);
  }
  if (content.length < minChars) {
    fail(`completion too short (${content.length} chars; need >= ${minChars}): ${JSON.stringify(content)}`);
  }
  if (/^!+$/.test(content) || /^\.{1,8}$/.test(content)) {
    fail(`degenerate completion refused: ${JSON.stringify(content)}`);
  }

  const lower = content.toLowerCase();
  const missing = required.filter((needle) => !lower.includes(needle));
  if (missing.length > 0) {
    fail(`completion missing required coding markers ${missing.join(', ')}: ${JSON.stringify(content.slice(0, 400))}`);
  }
  if (requireClampImpl) {
    const code = extractCode(content);
    const fenced = firstFence(content);
    if (fenced && fenced.tail.trim().length > 0) {
      fail(`completion had trailing text after first complete code fence: ${JSON.stringify(fenced.tail.slice(0, 300))}`);
    }
    const signature = /function\s+clamp\s*\(\s*value\s*:\s*number\s*,\s*min\s*:\s*number\s*,\s*max\s*:\s*number\s*\)\s*:\s*number\s*\{/m;
    const mathClamp = /return\s+Math\.(?:min|max)\s*\(\s*Math\.(?:max|min)\s*\(\s*value\s*,\s*(?:min|max)\s*\)\s*,\s*(?:max|min)\s*\)\s*;?/m;
    const branchClamp = /if\s*\(\s*value\s*<\s*min\s*\)\s*\{?\s*return\s+min\s*;?\s*\}?[\s\S]*if\s*\(\s*value\s*>\s*max\s*\)\s*\{?\s*return\s+max\s*;?\s*\}?[\s\S]*return\s+value\s*;?/m;
    if (!signature.test(code) || (!mathClamp.test(code) && !branchClamp.test(code))) {
      fail(`completion did not contain a valid typed clamp implementation: ${JSON.stringify(code.slice(0, 500))}`);
    }
  }

  console.log(
    `[codestral-openai-qspec] PASS model=${model} elapsed_ms=${elapsedMs} chars=${content.length} finish=${finishReason}`,
  );
  console.log(content.slice(0, 600));
} catch (error) {
  if (error?.name === 'TimeoutError') {
    fail(`request timed out after ${requestTimeoutMs}ms`);
  }
  fail(error instanceof Error ? error.message : String(error));
}

function argValue(name) {
  const index = process.argv.indexOf(name);
  if (index < 0 || index + 1 >= process.argv.length) return null;
  return process.argv[index + 1];
}

function stripTrailingSlash(value) {
  return value.replace(/\/+$/, '');
}

function readPositiveInt(name, fallback) {
  const raw = process.env[name];
  if (!raw) return fallback;
  const parsed = Number.parseInt(raw, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function parseJson(text) {
  try {
    return JSON.parse(text);
  } catch {
    fail(`response was not JSON: ${text.slice(0, 600)}`);
  }
}

function extractCode(content) {
  return (firstFence(content)?.code || content).trim();
}

function firstFence(content) {
  const fence = content.match(/```(?:typescript|ts)?\s*([\s\S]*?)```([\s\S]*)$/i);
  if (!fence) return null;
  return { code: fence[1] || '', tail: fence[2] || '' };
}

function fail(message) {
  console.error(`[codestral-openai-qspec] FAIL ${message}`);
  process.exit(2);
}
